import { AlertCircle, CheckCircle, X, Loader2, ChevronLeft, ChevronRight } from 'lucide-react';

// ─── Loading Spinner ───────────────────────────────────────
export const Spinner = ({ size = 'md', className = '' }) => {
  const sizes = { sm: 'w-4 h-4', md: 'w-6 h-6', lg: 'w-10 h-10' };
  return <Loader2 className={`animate-spin text-brand-400 ${sizes[size]} ${className}`} />;
};

// ─── Page Loading ─────────────────────────────────────────
export const PageLoader = () => (
  <div className="flex items-center justify-center h-64">
    <div className="flex flex-col items-center gap-3">
      <Spinner size="lg" />
      <p className="text-slate-500 text-sm">Đang tải...</p>
    </div>
  </div>
);

// ─── Empty State ──────────────────────────────────────────
export const EmptyState = ({ icon: Icon, title, desc, action }) => (
  <div className="flex flex-col items-center justify-center py-16 gap-4">
    <div className="w-16 h-16 rounded-2xl bg-slate-800 flex items-center justify-center">
      <Icon className="w-8 h-8 text-slate-600" />
    </div>
    <div className="text-center">
      <h3 className="text-slate-300 font-semibold mb-1">{title}</h3>
      <p className="text-slate-500 text-sm">{desc}</p>
    </div>
    {action}
  </div>
);

// ─── Error Alert ──────────────────────────────────────────
export const ErrorAlert = ({ message, onClose }) => (
  <div className="flex items-start gap-3 p-4 bg-red-500/10 border border-red-500/20 rounded-xl animate-fade-in">
    <AlertCircle className="w-5 h-5 text-red-400 flex-shrink-0 mt-0.5" />
    <p className="text-red-300 text-sm flex-1">{message}</p>
    {onClose && (
      <button onClick={onClose} className="text-red-400 hover:text-red-300">
        <X className="w-4 h-4" />
      </button>
    )}
  </div>
);

// ─── Modal ────────────────────────────────────────────────
export const Modal = ({ isOpen, onClose, title, children, size = 'md' }) => {
  if (!isOpen) return null;
  const sizes = { sm: 'max-w-md', md: 'max-w-lg', lg: 'max-w-2xl' };
  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 animate-fade-in">
      <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" onClick={onClose} />
      <div className={`relative glass rounded-2xl w-full ${sizes[size]} animate-scale-in shadow-2xl`}>
        <div className="flex items-center justify-between p-6 border-b border-slate-800">
          <h2 className="text-lg font-bold text-slate-100">{title}</h2>
          <button onClick={onClose} className="p-1.5 hover:bg-slate-800 rounded-lg transition-colors">
            <X className="w-5 h-5 text-slate-400" />
          </button>
        </div>
        <div className="p-6">{children}</div>
      </div>
    </div>
  );
};

// ─── Form Field ───────────────────────────────────────────
export const FormField = ({ label, error, children, required }) => (
  <div className="flex flex-col gap-1.5">
    <label className="text-sm font-medium text-slate-300">
      {label} {required && <span className="text-red-400">*</span>}
    </label>
    {children}
    {error && <p className="text-xs text-red-400">{error}</p>}
  </div>
);

// ─── Status Badge ─────────────────────────────────────────
export const StatusBadge = ({ status }) => {
  const map = {
    Pending:   'bg-yellow-500/10 text-yellow-400 border-yellow-500/20',
    Confirmed: 'bg-green-500/10  text-green-400  border-green-500/20',
    Cancelled: 'bg-red-500/10   text-red-400    border-red-500/20',
  };
  return (
    <span className={`badge border ${map[status] || 'bg-slate-700 text-slate-300'}`}>
      {status}
    </span>
  );
};

// ─── Confirm Dialog ───────────────────────────────────────
export const ConfirmDialog = ({ isOpen, onClose, onConfirm, title, message, loading }) => (
  <Modal isOpen={isOpen} onClose={onClose} title={title} size="sm">
    <p className="text-slate-400 mb-6">{message}</p>
    <div className="flex gap-3 justify-end">
      <button onClick={onClose} className="btn-secondary">Hủy</button>
      <button
        onClick={onConfirm}
        disabled={loading}
        className="bg-red-600 hover:bg-red-500 text-white font-semibold px-5 py-2.5 rounded-xl transition-all flex items-center gap-2 disabled:opacity-50"
      >
        {loading && <Spinner size="sm" />}
        Xác nhận xóa
      </button>
    </div>
  </Modal>
);

// ─── Stat Card ────────────────────────────────────────────
export const StatCard = ({ icon: Icon, label, value, color }) => (
  <div className="stat-card flex items-center gap-4">
    <div className={`w-12 h-12 rounded-xl flex items-center justify-center ${color}`}>
      <Icon className="w-6 h-6" />
    </div>
    <div>
      <p className="text-slate-500 text-sm">{label}</p>
      <p className="text-2xl font-bold text-slate-100">{value}</p>
    </div>
  </div>
);

// ─── Table Wrapper ────────────────────────────────────────
export const DataTable = ({ headers, children, loading, empty }) => (
  <div className="overflow-x-auto">
    <table className="w-full">
      <thead>
        <tr className="border-b border-slate-800">
          {headers.map((h, i) => (
            <th key={i} className="text-left text-xs font-semibold text-slate-500 uppercase tracking-wider py-3 px-4">
              {h}
            </th>
          ))}
        </tr>
      </thead>
      <tbody>
        {loading ? (
          <tr><td colSpan={headers.length} className="py-16 text-center"><Spinner className="mx-auto" /></td></tr>
        ) : empty ? (
          <tr><td colSpan={headers.length}>{empty}</td></tr>
        ) : children}
      </tbody>
    </table>
  </div>
);
